import React, { useState, useEffect } from 'react'
import { InputNumber, Table, Tag, Input } from 'antd';

const TableMaterial = (props) => {

    const [actualStock, setActualStock] = useState([])
    const [actualSerial, setActualSerial] = useState([])
    const [selectedRowKeys, setSelectedRowKeys] = useState([])

    useEffect(() => {
        props.actualStockMaterial(actualStock)
    }, [actualStock])

    useEffect(() => {
        props.actualSerialMaterial(actualSerial)
    }, [actualSerial])

    useEffect(() => {
        if (props.selectedMaterial.length > 0) {
            let stocks = []
            props.selectedMaterial.map((item, index) => {
                stocks[index] = { id: item.stock.id, val: item.actual_stock }
            })
            let newActualStock = [...actualStock, ...stocks]
            setActualStock(newActualStock)

            let serials = []
            props.selectedMaterial.map(item => {
                if (item.serials) {
                    item.serials.map((value, key) => {
                        serials.push({ id: item.stock.id, key, val: value.serial_number })
                    })
                }
            })
            let newActualSerial = [...actualSerial, ...serials]
            setActualSerial(newActualSerial)
        }
    }, [props.selectedMaterial])

    const handleChangeActualStock = (id, val) => {
        let stock = [{ id, val }]
        let newActualStock = [...actualStock, ...stock]
        setActualStock(newActualStock)
    }

    const handleChangeActualSerial = (id, i, e) => {
        let serials = [{ id, key: i, val: e.target.value }]
        let newActualSerial = [...actualSerial, ...serials]
        setActualSerial(newActualSerial)
    }

    //on check table item
    const onSelectChange = (selectedRowKeys) => {
        setSelectedRowKeys(selectedRowKeys)
        props.selectedMaterialDelete(selectedRowKeys)
    }

    const rowSelection = {
        selectedRowKeys,
        onChange: onSelectChange,
    };

    const columns = [
        {
            title: 'Material Code',
            dataIndex: 'material',
            width: 200,
            render: (material) => {
                if (material) { return material.material_code }
            },
        },
        {
            title: 'System Stock',
            dataIndex: 'stock',
            width: 80,
            className: 'col-number',
        },
        {
            title: 'Existing Serial',
            dataIndex: 'stock_details',
            render: (stock_details, record) => {
                if (stock_details && record.material.serial_number) {
                    let serials = stock_details.map(item => (
                        item.serial_number && <Tag key={item.id}>{item.serial_number}</Tag>
                    ))

                    return serials
                } else {
                    return <Tag color="#2db7f5">Serial is not required</Tag>
                }
            },
            width: 150,
            className: 'col-center',
        },
        {
            title: 'Actual Stock',
            dataIndex: 'id',
            render: (id) => {
                if (props.edit || props.view) {
                    let index = actualStock.map(item => item.id).lastIndexOf(id)
                    return <InputNumber
                        min={0}
                        size="small"
                        readOnly={props.view}
                        value={
                            actualStock[index] && actualStock[index].id === id
                                ? actualStock[index].val
                                : 0
                        }
                        onChange={(id, (val) => handleChangeActualStock(id, val))} />
                }
            },
            width: 80,
        },
        {
            title: 'Actual Serial',
            dataIndex: 'id',
            render: (id, record) => {
                if ((props.edit || props.view) && record.material.serial_number) {
                    let indexStock = actualStock.map(item => item.id).lastIndexOf(id)
                    let stock = actualStock[indexStock] ? actualStock[indexStock].val : 0
                    let serialInput = [];
                    for (let i = 0; i < parseInt(stock); i++) {
                        let indexSerial = actualSerial.map(item => { if (item.id === id && item.key === i) { return item.id } }).lastIndexOf(id)
                        serialInput.push(
                            <div style={{ padding: 2 }} key={i}>
                                <Input
                                    readOnly={props.view}
                                    size="small"
                                    style={{ width: '100%' }}
                                    value={
                                        actualSerial[indexSerial] && actualSerial[indexSerial].id === id && actualSerial[indexSerial].key === i
                                            ? actualSerial[indexSerial].val
                                            : ''
                                    }
                                    onChange={(id, i), (e) => handleChangeActualSerial(id, i, e)} />
                            </div>
                        );
                    }

                    return serialInput
                }
            },
            width: 200,
            className: 'col-center',
        },
        {
            title: 'Description',
            dataIndex: 'material',
            width: 300,
            render: (material) => {
                if (material) { return material.description }
            },
        },
        {
            title: 'Classification',
            dataIndex: 'material',
            width: 200,
            render: (material) => {
                if (material && material.classification) { return material.classification.name }
            },
        },
        {
            title: 'UoM',
            dataIndex: 'material',
            render: (material) => {
                if (material && material.uom) { return material.uom.name }
            },
            width: 100
        },
    ];
    return (
        <Table
            rowSelection={rowSelection}
            rowKey={record => record.id}
            dataSource={props.add ? props.selectedMaterial : props.selectedMaterial.map(item => item.stock)}
            columns={columns}
            pagination={false}
            size="small"
            bordered
            scroll={{ x: 1000 }} />
    )
}

export default TableMaterial;